import API from "./api";

// ===============================
// AUTH APIs
// ===============================
export const login = async (data) => {
  try {
    const res = await API.post("/auth/login", data);
    return res?.data || null;
  } catch (err) {
    console.error("Login Error:", err.response?.data || err.message);
    return null;
  }
};

export const register = async (data) => {
  try {
    const res = await API.post("/auth/register", data);
    return res?.data || null;
  } catch (err) {
    console.error("Register Error:", err.response?.data || err.message);
    return null;
  }
};

// ===============================
// USER APIs
// ===============================
export const getProfile = async (username) => {
  try {
    if (!username) return null;

    const res = await API.get(`/user/${username.trim()}`);
    return res?.data || null;
  } catch (err) {
    console.error("Profile Error:", err.response?.status, err.response?.data);
    return null;
  }
};

// ===============================
// CRICKET APIs
// ===============================
export const getLiveMatches = async () => {
  try {
    const res = await API.get("/cricket/live");
    return res?.data || [];
  } catch (err) {
    console.error("Live Matches Error:", err.response?.data || err.message);
    return [];
  }
};

export const getPlayerStats = async (name) => {
  try {
    if (!name) return null;

    const res = await API.get(`/cricket/player?name=${name}`);
    return res?.data || null;
  } catch (err) {
    console.error("Player Stats Error:", err.response?.data || err.message);
    return null;
  }
};

export const getSchedule = async () => {
  try {
    const res = await API.get("/cricket/schedule");
    return res?.data || [];
  } catch (err) {
    console.error("Schedule Error:", err.response?.data || err.message);
    return [];
  }
};

// ===============================
// CHAT API
// ===============================
export const sendChat = async (message) => {
  try {
    if (!message) return null;

    const res = await API.post("/chat/", { message }); // âš ď¸Ź trailing slash FIX
    return res?.data || null;
  } catch (err) {
    console.error("Chat Error:", err.response?.status, err.response?.data);
    return null;
  }
};

// ===============================
// INSIGHTS API
// ===============================
export const getInsights = async (player) => {
  try {
    if (!player) return null;

    const res = await API.get(`/insights/?player=${player}`); // âš ď¸Ź slash FIX
    return res?.data || null;
  } catch (err) {
    console.error("Insights Error:", err.response?.data || err.message);
    return null;
  }
};

// ===============================
// KNOWLEDGE API
// ===============================
export const searchKnowledge = async (query) => {
  try {
    if (!query) return null;

    const res = await API.get(`/knowledge/?q=${query}`); // âš ď¸Ź slash FIX
    return res?.data || null;
  } catch (err) {
    console.error("Knowledge Error:", err.response?.data || err.message);
    return null;
  }
};
